    private double[] arrayB;
    private double x;
    private double y;
    private boolean result;

    @Given("two double arrays {string} and {string}")
    public void two_double_arrays_and(String arrayAName, String arrayBName) {
        arrayA = new double[1];
        arrayB = new double[1];
    }

    @Given("array {string} contains a NaN value")
    public void array_contains_a_nan_value(String arrayName) {
        if ("a".equals(arrayName)) {
            arrayA[0] = Double.NaN;
        }
    }

    @Given("array {string} contains a NaN value at the same index")
    public void array_contains_a_nan_value_at_the_same_index(String arrayBName) {
        arrayB[0] = Double.NaN;
    }

