        try {
            result = MathUtils.equals(arrayA, arrayB);
        } catch (Exception e) {
            result = false; // or handle exception as appropriate
        }
    }

    @Then("the result should be false")
    public void the_result_should_be_false() {
        assertFalse("MathUtils.equals should return false for arrays containing NaNs", result);
    }

    @Given("two double values {string} and {string}")
    public void two_double_values_and(String xName, String yName) {
        // x and y are already defined as fields
    }

    @Given("{string} is NaN")
    public void is_nan(String varName) {
        if ("x".equals(varName)) {
            x = Double.NaN;
        } else if ("y".equals(varName)) {
            y = Double.NaN;
        }
    }

    @When("MathUtils.equals(x, y) is called")
    public void mathutils_equals_x_y_is_called() {
        try {
            result = MathUtils.equals(x, y);
        } catch (Exception e) {
            result = false; // or handle exception as appropriate
        }
    }

    @Given("{string} is {double}")
    public void is_value(String varName, double value) {
        if ("x".equals(varName)) {
            x = value;
        } else if ("y".equals(varName)) {
            y = value;
        }
    }

    @When("MathUtils.equals(x, y) is called")
    public void mathutils_equals_x_y_is_called_again() {
        try {
            result = MathUtils.equals(x, y);
        } catch (Exception e) {
            result = false; // or handle exception as appropriate
        }
